export function toolIdToLegacy(tool: ToolId): LegacyPlanTool | null {
  if (KNOWN_PLAN_TOOLS.has(tool)) return tool as LegacyPlanTool;
  return null;
}

export function legacyToToolId(legacy: LegacyPlanTool): ToolId {
  if (legacy === 'room_rectangle') return 'room';
  if (legacy === 'grid') return 'grid';
  return legacy as ToolId;
}

export function buildBrowserSections(elementsById: Record<string, Element>): LeftRailSection[] {
  const all = Object.values(elementsById) as Element[];
  const levels = all
    .filter((e): e is Extract<Element, { kind: 'level' }> => e.kind === 'level')
    .sort((a, b) => a.elevationMm - b.elevationMm);
  const allPlanViews = all.filter(
    (e): e is Extract<Element, { kind: 'plan_view' }> => e.kind === 'plan_view',
  );
  const planViews = allPlanViews.filter((p) => p.planViewSubtype !== 'area_plan');
  const areaPlans = allPlanViews.filter((p) => p.planViewSubtype === 'area_plan');
  const viewpoints = all.filter(
    (e): e is Extract<Element, { kind: 'viewpoint' }> => e.kind === 'viewpoint',
  );
  const sections = all.filter(
    (e): e is Extract<Element, { kind: 'section_cut' }> => e.kind === 'section_cut',
  );
  const sheets = all.filter((e): e is Extract<Element, { kind: 'sheet' }> => e.kind === 'sheet');
  const schedules = all.filter(
    (e): e is Extract<Element, { kind: 'schedule' }> => e.kind === 'schedule',
  );
  return [
    {
      id: 'project',
      label: 'Project',
      icon: LevelIcon,
      rows: [
        {
          id: 'levels',
          label: 'Levels',
          children: levels.map((l) => ({ id: l.id, label: l.name, hint: `${l.elevationMm}mm` })),
        },
      ],
    },
    {
      id: 'views',
      label: 'Views',
      icon: PlanViewIcon,
      rows: [
        {
          id: 'plans',
          label: 'Floor Plans',
          children: planViews.map((p) => ({ id: p.id, label: p.name })),
        },
        {
          id: 'viewpoints',
          label: '3D Views',
          children: viewpoints.map((v) => ({ id: v.id, label: v.name })),
        },
        {
          id: 'sections',
          label: 'Sections',
          children: sections.map((s) => ({ id: s.id, label: s.name })),
        },
        ...(areaPlans.length > 0
          ? [
              {
                id: 'area-plans',
                label: 'Area Plans',
                children: areaPlans.map((p) => ({ id: p.id, label: p.name })),
              },
            ]
          : []),
      ],
    },
    {
      id: 'sheets',
      label: 'Sheets',
      icon: SheetIcon,
      rows: sheets.map((s) => ({ id: s.id, label: s.name })),
    },
    {
      id: 'schedules',
      label: 'Schedules',
      icon: ScheduleViewIcon,
      rows: schedules.map((s) => ({ id: s.id, label: s.name })),
    },
    {
      id: 'types',
      label: 'Types',
      icon: WallLayerIcon,
      rows: [
        {
          id: 'wall-types',
          label: 'Wall Types',
          children: [
            ...all
              .filter((e): e is Extract<Element, { kind: 'wall_type' }> => e.kind === 'wall_type')
              .map((t) => ({ id: t.id, label: t.name, hint: `${t.layers.length} layers` })),
            { id: 'new-wall-type', label: '+ New Wall Type' },
          ],
        },
        {
          id: 'floor-types',
          label: 'Floor Types',
          children: [
            ...all
              .filter((e): e is Extract<Element, { kind: 'floor_type' }> => e.kind === 'floor_type')
              .map((t) => ({ id: t.id, label: t.name, hint: `${t.layers.length} layers` })),
            { id: 'new-floor-type', label: '+ New Floor Type' },
          ],
        },
        {
          id: 'roof-types',
          label: 'Roof Types',
          children: [
            ...all
              .filter((e): e is Extract<Element, { kind: 'roof_type' }> => e.kind === 'roof_type')
              .map((t) => ({ id: t.id, label: t.name, hint: `${t.layers.length} layers` })),
            { id: 'new-roof-type', label: '+ New Roof Type' },
          ],
        },
      ],
    },
    {
      id: 'families',
      label: 'Families',
      icon: FamilyIcon,
      rows: (['door', 'window', 'stair', 'railing'] as const)
        .map((disc) => {
          const discLabel = (
            { door: 'Doors', window: 'Windows', stair: 'Stairs', railing: 'Railings' } as const
          )[disc];
          const customOfDisc = all.filter(
            (e): e is Extract<Element, { kind: 'family_type' }> =>
              e.kind === 'family_type' && e.discipline === disc,
          );
          const builtInRows = BUILT_IN_FAMILIES.filter((f) => f.discipline === disc).map((fam) => ({
            id: fam.id,
            label: fam.name,
            children: fam.defaultTypes.map((t) => ({ id: t.id, label: t.name })),
          }));
          const customRows = customOfDisc.map((ct) => ({
            id: ct.id,
            label: String(ct.parameters.name ?? ct.id),
            hint: 'custom',
          }));
          return {
            id: `fam-group-${disc}`,
            label: discLabel,
            children: [...builtInRows, ...customRows],
          };
        })
        .filter((g) => g.children.length > 0),
    },
  ];
}

export function buildPaletteCandidates(
  elementsById: Record<string, Element>,
  toolRegistry: Record<string, { id: ToolId; label: string; tooltip?: string; hotkey: string }>,
  t: TFunction,
): CommandCandidate[] {
  const items: CommandCandidate[] = [];
  for (const tool of Object.values(toolRegistry)) {
    items.push({
      id: `tool.${tool.id}`,
      kind: 'tool',
      label: tool.label,
      keywords: tool.tooltip ?? '',
      hint: tool.hotkey,
    });
  }
  for (const el of Object.values(elementsById) as Element[]) {
    if (el.kind === 'plan_view') {
      items.push({ id: el.id, kind: 'view', label: `Plan: ${el.name}`, keywords: 'plan view' });
    } else if (el.kind === 'viewpoint') {
      items.push({ id: el.id, kind: 'view', label: `3D: ${el.name}`, keywords: 'viewpoint orbit' });
    } else if (el.kind === 'section_cut') {
      items.push({
        id: el.id,
        kind: 'view',
        label: `Section: ${el.name}`,
        keywords: 'section cut',
      });
    }
  }
  let elemCount = 0;
  for (const el of Object.values(elementsById) as Element[]) {
    if (el.kind !== 'wall' && el.kind !== 'door' && el.kind !== 'window' && el.kind !== 'room')
      continue;
    if (elemCount > 60) break;
    items.push({
      id: el.id,
      kind: 'element',
      label: `${el.kind}: ${(el as { name?: string }).name ?? el.id}`,
      keywords: el.kind,
    });
    elemCount++;
  }
  items.push(
    { id: 'settings.theme.light', kind: 'setting', label: 'Theme: light', keywords: 'light' },
    { id: 'settings.theme.dark', kind: 'setting', label: 'Theme: dark', keywords: 'dark' },
    {
      id: 'settings.language.toggle',
      kind: 'setting',
      label: t('cmd.language'),
      keywords: 'language lang sprache',
    },
  );
  items.push({
    id: 'tool.browse-families',
    kind: 'tool',
    label: 'Browse families',
    keywords: 'family library catalog door window stair railing wall type',
  });
  items.push({ id: 'agent.review', kind: 'agent', label: 'Run Agent Review' });
  return items;
}

import { beforeEach, describe, expect, it, vi } from 'vitest';
import { clearQueue, drainQueue, enqueueCommand, getQueueLength } from '../commandQueue';
import type { OfflineSyncBadge } from '@bim-ai/core';

// Reset module-level queue between tests
beforeEach(() => {
  clearQueue();
});

// ---------------------------------------------------------------------------
// Minimal offline store logic under test (extracted from offlineStore.ts)
// Tested here without the Zustand dependency to keep the test file self-contained
// in the worktree environment where node_modules are not installed locally.
// ---------------------------------------------------------------------------

type OfflineState = {
  isOnline: boolean;
  pendingCommandCount: number;
  lastSyncedAt: string | null;
  offlineQueuedAt: string | null;
};

function makeOfflineStore(initial: OfflineState) {
  let state = { ...initial };
  return {
    getState: () => ({ ...state }),
    setOnline(isOnline: boolean) {
      state = {
        ...state,
        isOnline,
        offlineQueuedAt:
          !isOnline && state.isOnline ? new Date().toISOString() : state.offlineQueuedAt,
      };
    },
    incrementPendingCount() {
      state = { ...state, pendingCommandCount: state.pendingCommandCount + 1 };
    },
    clearPendingCount() {
      state = { ...state, pendingCommandCount: 0, lastSyncedAt: new Date().toISOString() };
    },
  };
}

describe('commandQueue', () => {
  it('enqueueCommand adds to queue', () => {
    enqueueCommand({ type: 'createWall' }, 'model-1');
    expect(getQueueLength()).toBe(1);
  });

  it('getQueueLength returns correct count', () => {
    expect(getQueueLength()).toBe(0);
    enqueueCommand({ type: 'createWall' }, 'model-1');
    enqueueCommand({ type: 'deleteElements', elementIds: ['w1'] }, 'model-1');
    expect(getQueueLength()).toBe(2);
  });

  it('drainQueue calls applyBundle once per modelId', async () => {
    enqueueCommand({ type: 'createWall' }, 'model-a');
    enqueueCommand({ type: 'createFloor' }, 'model-b');
    enqueueCommand({ type: 'createRoom' }, 'model-a');

    const applyBundle = vi.fn().mockResolvedValue(undefined);
    await drainQueue(applyBundle);

    expect(applyBundle).toHaveBeenCalledTimes(2);
  });

  it('drainQueue groups commands by modelId', async () => {
    const cmdA1 = { type: 'createWall' };
    const cmdA2 = { type: 'createRoom' };
    const cmdB1 = { type: 'createFloor' };
    enqueueCommand(cmdA1, 'model-a');
    enqueueCommand(cmdA2, 'model-a');
    enqueueCommand(cmdB1, 'model-b');

    const applyBundle = vi.fn().mockResolvedValue(undefined);
    await drainQueue(applyBundle);

    const callsForA = applyBundle.mock.calls.find(([id]) => id === 'model-a');
    const callsForB = applyBundle.mock.calls.find(([id]) => id === 'model-b');
    expect(callsForA?.[1]).toHaveLength(2);
    expect(callsForB?.[1]).toHaveLength(1);
  });

  it('drainQueue clears queue on full success', async () => {
    enqueueCommand({ type: 'createWall' }, 'model-1');
    enqueueCommand({ type: 'createFloor' }, 'model-1');

    const applyBundle = vi.fn().mockResolvedValue(undefined);
    await drainQueue(applyBundle);

    expect(getQueueLength()).toBe(0);
  });

  it('drainQueue preserves queue on error', async () => {
    enqueueCommand({ type: 'createWall' }, 'model-fail');

    const applyBundle = vi.fn().mockRejectedValue(new Error('network error'));
    await drainQueue(applyBundle);

    expect(getQueueLength()).toBe(1);
  });

  it('drainQueue returns correct {drained, errors} on success', async () => {
    enqueueCommand({ type: 'createWall' }, 'model-1');
    enqueueCommand({ type: 'createFloor' }, 'model-1');

    const applyBundle = vi.fn().mockResolvedValue(undefined);
    const result = await drainQueue(applyBundle);

    expect(result).toEqual({ drained: 2, errors: 0 });
  });

  it('drainQueue returns correct {drained, errors} on partial failure', async () => {
    enqueueCommand({ type: 'createWall' }, 'model-ok');
    enqueueCommand({ type: 'createFloor' }, 'model-fail');

    const applyBundle = vi.fn().mockImplementation((modelId: string) => {
      if (modelId === 'model-fail') return Promise.reject(new Error('fail'));
      return Promise.resolve();
    });
    const result = await drainQueue(applyBundle);

    expect(result.drained).toBe(1);
    expect(result.errors).toBe(1);
  });

  it('drainQueue on empty queue returns {drained:0, errors:0}', async () => {
    const applyBundle = vi.fn();
    const result = await drainQueue(applyBundle);

    expect(result).toEqual({ drained: 0, errors: 0 });
    expect(applyBundle).not.toHaveBeenCalled();
  });

  it('multiple modelIds produce separate applyBundle calls', async () => {
    enqueueCommand({ type: 'cmd-1' }, 'model-x');
    enqueueCommand({ type: 'cmd-2' }, 'model-y');
    enqueueCommand({ type: 'cmd-3' }, 'model-z');

    const applyBundle = vi.fn().mockResolvedValue(undefined);
    await drainQueue(applyBundle);

    expect(applyBundle).toHaveBeenCalledTimes(3);
    const calledModelIds = applyBundle.mock.calls.map(([id]: [string, ...unknown[]]) => id).sort();
    expect(calledModelIds).toEqual(['model-x', 'model-y', 'model-z']);
  });

  it('clearQueue empties the queue', () => {
    enqueueCommand({ type: 'createWall' }, 'model-1');
    enqueueCommand({ type: 'createFloor' }, 'model-1');
    clearQueue();
    expect(getQueueLength()).toBe(0);
  });

  it('OfflineSyncBadge TS type round-trip', () => {
    const badge: OfflineSyncBadge = {
      kind: 'offline_sync_badge',
      commandCount: 3,
      offlineQueuedAt: '2026-05-09T10:00:00.000Z',
      syncedAt: '2026-05-09T10:05:00.000Z',
    };
    // Type assertion — verifies the type is structurally correct at compile time
    expect(badge.kind).toBe('offline_sync_badge');
    expect(badge.commandCount).toBe(3);
  });
});

describe('offlineStore logic', () => {
  it('setOnline(false) sets offlineQueuedAt', () => {
    const store = makeOfflineStore({
      isOnline: true,
      pendingCommandCount: 0,
      lastSyncedAt: null,
      offlineQueuedAt: null,
    });

    store.setOnline(false);

    const state = store.getState();
    expect(state.isOnline).toBe(false);
    expect(state.offlineQueuedAt).not.toBeNull();
  });

  it('setOnline(true) when already online does NOT change offlineQueuedAt', () => {
    const store = makeOfflineStore({
      isOnline: true,
      pendingCommandCount: 0,
      lastSyncedAt: null,
      offlineQueuedAt: 'existing-ts',
    });

    store.setOnline(true);

    expect(store.getState().offlineQueuedAt).toBe('existing-ts');
  });

  it('incrementPendingCount increments count', () => {
    const store = makeOfflineStore({
      isOnline: true,
      pendingCommandCount: 0,
      lastSyncedAt: null,
      offlineQueuedAt: null,
    });

    store.incrementPendingCount();
    store.incrementPendingCount();

    expect(store.getState().pendingCommandCount).toBe(2);
  });

  it('clearPendingCount resets to 0 and sets lastSyncedAt', () => {
    const store = makeOfflineStore({
      isOnline: true,
      pendingCommandCount: 5,
      lastSyncedAt: null,
      offlineQueuedAt: null,
    });

    store.clearPendingCount();

    const state = store.getState();
    expect(state.pendingCommandCount).toBe(0);
    expect(state.lastSyncedAt).not.toBeNull();
  });
});

